package scheduler

import (
	"fmt"
	"strconv"
	"strings"
	"time"
)

type CronField struct {
	All      bool
	Interval int   // for */N
	Values   []int // specific values
}

type CronExpr struct {
	Minute CronField
	Hour   CronField
	Day    CronField
}

func parseField(s string) (CronField, error) {
	s = strings.TrimSpace(s)
	if s == "*" {
		return CronField{All: true}, nil
	}
	if strings.HasPrefix(s, "*/") {
		n, err := strconv.Atoi(s[2:])
		if err != nil || n <= 0 {
			return CronField{}, fmt.Errorf("invalid interval: %s", s)
		}
		return CronField{Interval: n}, nil
	}
	n, err := strconv.Atoi(s)
	if err != nil {
		return CronField{}, fmt.Errorf("invalid value: %s", s)
	}
	return CronField{Values: []int{n}}, nil
}

func ParseCron(expr string) (*CronExpr, error) {
	parts := strings.Fields(expr)
	if len(parts) != 3 {
		return nil, fmt.Errorf("cron expr needs 3 fields (min hour day), got %d", len(parts))
	}
	minute, err := parseField(parts[0])
	if err != nil {
		return nil, err
	}
	hour, err := parseField(parts[1])
	if err != nil {
		return nil, err
	}
	day, err := parseField(parts[2])
	if err != nil {
		return nil, err
	}
	return &CronExpr{Minute: minute, Hour: hour, Day: day}, nil
}

func (f CronField) matches(value int) bool {
	if f.All {
		return true
	}
	if f.Interval > 0 {
		return value%f.Interval == 0
	}
	for _, v := range f.Values {
		if v == value {
			return true
		}
	}
	return false
}

func (c *CronExpr) Matches(t time.Time) bool {
	return c.Minute.matches(t.Minute()) &&
		c.Hour.matches(t.Hour()) &&
		c.Day.matches(t.Day())
}

package scheduler

import (
	"testing"
	"time"
)

func TestParseCronAllWildcards(t *testing.T) {
	c, err := ParseCron("* * *")
	if err != nil {
		t.Fatal(err)
	}
	now := time.Now()
	if !c.Matches(now) {
		t.Error("expected all wildcards to match any time")
	}
}

func TestParseCronInterval(t *testing.T) {
	c, _ := ParseCron("*/5 * *")
	t1 := time.Date(2024, 1, 1, 10, 0, 0, 0, time.UTC)
	if !c.Matches(t1) {
		t.Error("minute 0 should match */5")
	}
	t2 := time.Date(2024, 1, 1, 10, 3, 0, 0, time.UTC)
	if c.Matches(t2) {
		t.Error("minute 3 should not match */5")
	}
}

func TestParseCronSpecific(t *testing.T) {
	c, _ := ParseCron("30 14 *")
	match := time.Date(2024, 1, 1, 14, 30, 0, 0, time.UTC)
	if !c.Matches(match) {
		t.Error("expected 14:30 to match")
	}
	noMatch := time.Date(2024, 1, 1, 15, 30, 0, 0, time.UTC)
	if c.Matches(noMatch) {
		t.Error("expected 15:30 to not match")
	}
}

func TestParseCronInvalid(t *testing.T) {
	_, err := ParseCron("invalid")
	if err == nil {
		t.Error("expected error for invalid expression")
	}
}
